$imgDir = "c:\Users\ThinkPad\Documents\GitHub\minigames2026\postdiy\tools\music\img\saxophone"
[System.IO.Directory]::CreateDirectory($imgDir) | Out-Null

$utf8 = [System.Text.Encoding]::UTF8

function Save-Svg {
    param([string]$Name, [string]$Content)
    [System.IO.File]::WriteAllText((Join-Path $imgDir $Name), $Content, $utf8)
    Write-Host "  OK $Name" -ForegroundColor Green
}

